#!/usr/bin/env bash
# sync-agent-instructions.sh — Generate fat AGENTS.md for non-Claude agents
#
# Claude uses @path imports (native inline). Every other agent needs shared
# modules concatenated into a single AGENTS.md so the full policy is in the
# system prompt from turn 1, with zero manual reads.
#
# Module selection is per-agent. To change which modules an agent gets,
# edit the AGENT_MODULES array below.
#
# Usage:
#   sync-agent-instructions.sh [--check]
#     --check   Exit 1 if any generated file is stale (used by dotfiles check)

set -euo pipefail

DOTFILES_DIR="${DOTFILES_DIR:-$(cd "$(dirname "$0")/../.." && pwd)}"
AGENTS_DIR="$DOTFILES_DIR/configs/agents"
CHECK_MODE=0
STALE=0

if [[ "${1:-}" == "--check" ]]; then
    CHECK_MODE=1
fi

# --- Per-agent module selection ---
# Each agent gets a space-separated list of modules (order matters — policy first).
# To add/remove a module for a specific agent, edit only that line.
declare -A AGENT_MODULES=(
    [omp]="policy.md rigour.md research.md version-control.md visual-testing.md agent-orchestration.md fidelity.md"
    [pi]="policy.md rigour.md research.md version-control.md visual-testing.md agent-orchestration.md fidelity.md"
    [codex]="policy.md research.md version-control.md fidelity.md"
    [cursor-agent]="policy.md research.md version-control.md visual-testing.md fidelity.md"
)

# On-demand modules: referenced but NOT inlined (same for all agents).
ON_DEMAND_MODULES=(
    "engineering-principles.md"
    "dev-env.md"
    "work.md"
)

# --- Agent → tool appendix mapping ---
declare -A AGENT_TOOL_APPENDIX=(
    [omp]="tools/omp.md"
    [pi]="tools/pi.md"
    [codex]="tools/codex.md"
    [cursor-agent]="tools/cursor-agent.md"
)

# --- Agent → output file mapping ---
declare -A AGENT_OUTPUT=(
    [omp]="$DOTFILES_DIR/configs/omp/AGENTS.md"
    [pi]="$DOTFILES_DIR/configs/pi/AGENTS.md"
    [codex]="$DOTFILES_DIR/configs/codex/AGENTS.md"
    [cursor-agent]="$DOTFILES_DIR/configs/cursor-agent/AGENTS.md"
)

generate_agents_md() {
    local agent="$1"
    local appendix_file="$AGENTS_DIR/${AGENT_TOOL_APPENDIX[$agent]}"
    local output=""

    # Header
    output+="<!-- GENERATED by scripts/generated/sync-agent-instructions.sh — do not edit -->"
    output+=$'\n'
    output+="<!-- Edit source modules in configs/agents/, then run: dotfiles regen -->"
    output+=$'\n\n'

    # Agent-specific modules
    IFS=' ' read -ra modules <<< "${AGENT_MODULES[$agent]}"
    for mod in "${modules[@]}"; do
        local mod_path="$AGENTS_DIR/$mod"
        if [[ -f "$mod_path" ]]; then
            output+="$(cat "$mod_path")"
            output+=$'\n\n'
        else
            echo "WARNING: missing module $mod_path" >&2
        fi
    done

    # Tool-specific appendix
    if [[ -f "$appendix_file" ]]; then
        output+="$(cat "$appendix_file")"
        output+=$'\n\n'
    fi

    # On-demand references
    output+="## Context files (load on demand)"
    output+=$'\n\n'
    for mod in "${ON_DEMAND_MODULES[@]}"; do
        output+="- \`~/.config/agents/$mod\`"
        output+=$'\n'
    done
    output+=$'\n'
    output+="Repo-local \`AGENTS.md\` is authoritative when present."
    output+=$'\n'

    printf '%s' "$output"
}

for agent in "${!AGENT_OUTPUT[@]}"; do
    output_file="${AGENT_OUTPUT[$agent]}"
    expected="$(generate_agents_md "$agent")"

    if [[ "$CHECK_MODE" == "1" ]]; then
        if [[ ! -f "$output_file" ]] || [[ "$(cat "$output_file")" != "$expected" ]]; then
            echo "STALE: $output_file" >&2
            STALE=1
        fi
    else
        mkdir -p "$(dirname "$output_file")"
        printf '%s' "$expected" > "$output_file"
    fi
done

if [[ "$CHECK_MODE" == "1" && "$STALE" == "1" ]]; then
    echo "Run 'dotfiles regen' to update agent instructions." >&2
    exit 1
fi
